Page({
  data: {
    videoUrl: '',
    poster: ''
  },

  onLoad(options) {
    const raw = options.url || ''
    const url = raw ? decodeURIComponent(raw) : ''
    if (!url) {
      wx.showToast({ title: '无效视频地址', icon: 'none' })
      setTimeout(() => wx.navigateBack(), 1500)
      return
    }
    const posterRaw = options.poster || ''
    const poster = posterRaw ? decodeURIComponent(posterRaw) : ''
    this.setData({ videoUrl: url, poster })
  },

  onReady() {
    if (!this.data.videoUrl) return
    setTimeout(() => {
      try {
        const ctx = wx.createVideoContext('player', this)
        if (ctx && typeof ctx.requestFullScreen === 'function') {
          ctx.requestFullScreen({ direction: 90 })
        }
      } catch (e) {}
    }, 350)
  },

  onFullScreenChange(e) {
    const fullScreen = e.detail && e.detail.fullScreen
    if (!fullScreen) {
      wx.navigateBack()
    }
  }
})
